    this.error = '';
    this.searchQuery = '';
    this.sortKey = 'date';
    this.sortDir = 'asc';
    // Pagination
    this.pageSize = 12;
    this.currentPage = 1;
    // Date order for sorting
    this.dateOrder = ['Feb 26', 'Mar 5', 'Mar 10', 'Mar 18', 'Mar 20', 'Mar 24', 'Mar 25'];
  }
