  getSortIcon(key) {
    if (this.sortKey !== key) return '↕';
    return this.sortDir === 'asc' ? '↑' : '↓';
  }
  // Stats for current filter
  get filteredTotal() {
    return parseFloat(this.filteredTransactions.reduce((s, t) => s + t.amount, 0).toFixed(2));
