import { Component, OnInit } from '@angular/core';
import { DataService, Transaction } from '../../services/data.service';

type SortKey = 'date' | 'name' | 'amount';
type SortDir = 'asc' | 'desc';

@Component({
  selector: 'app-transactions',
  templateUrl: './transactions.component.html',
  styleUrls: ['./transactions.component.css']
})
export class TransactionsComponent implements OnInit {
  allTransactions: Transaction[] = [];
  filteredTransactions: Transaction[] = [];
  loading = true;
  error = '';

  searchQuery = '';
  sortKey: SortKey = 'date';
  sortDir: SortDir = 'asc';

  // Pagination
  pageSize = 12;
  currentPage = 1;

  // Date order for sorting
  private dateOrder = [
    'Feb 26', 'Mar 5', 'Mar 10', 'Mar 18', 'Mar 20', 'Mar 24', 'Mar 25'
  ];

  constructor(private dataService: DataService) {}

  ngOnInit(): void {
    this.loadTransactions();
  }

  loadTransactions(): void {
    this.loading = true;
    this.error = '';
    this.dataService.getTransactions().subscribe({
      next: (data) => {
        this.allTransactions = data;
        this.applyFilters();
        this.loading = false;
      },
      error: (err) => {
        this.error = 'Failed to load transactions. Is the backend running?';
        this.loading = false;
        console.error(err);
      }
    });
  }

  onSearch(): void {
    this.currentPage = 1;
    this.applyFilters();
  }

  clearSearch(): void {
    this.searchQuery = '';
    this.currentPage = 1;
    this.applyFilters();
  }

  setSort(key: SortKey): void {
    if (this.sortKey === key) {
      this.sortDir = this.sortDir === 'asc' ? 'desc' : 'asc';
    } else {
      this.sortKey = key;
      this.sortDir = key === 'amount' ? 'asc' : 'asc';
    }
    this.applyFilters();
  }

  private applyFilters(): void {
    let result = [...this.allTransactions];

    // Filter by search
    const q = this.searchQuery.toLowerCase().trim();
    if (q) {
      result = result.filter(t =>
        t.name.toLowerCase().includes(q) ||
        t.date.toLowerCase().includes(q) ||
        String(t.amount).includes(q) ||
        (t.transactionHash && t.transactionHash.toLowerCase().includes(q))
      );
    }

    // Sort
    result.sort((a, b) => {
      let cmp = 0;
      if (this.sortKey === 'date') {
        const ai = this.dateOrder.indexOf(a.date);
        const bi = this.dateOrder.indexOf(b.date);
        cmp = (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
      } else if (this.sortKey === 'name') {
        cmp = a.name.localeCompare(b.name);
      } else if (this.sortKey === 'amount') {
        cmp = a.amount - b.amount;
      }
      return this.sortDir === 'asc' ? cmp : -cmp;
    });

    this.filteredTransactions = result;
  }

  get totalPages(): number {
    return Math.ceil(this.filteredTransactions.length / this.pageSize);
  }

  get paginatedTransactions(): Transaction[] {
    const start = (this.currentPage - 1) * this.pageSize;
    return this.filteredTransactions.slice(start, start + this.pageSize);
  }

  get pageNumbers(): number[] {
    return Array.from({ length: this.totalPages }, (_, i) => i + 1);
  }

  goToPage(p: number): void {
    if (p >= 1 && p <= this.totalPages) {
      this.currentPage = p;
    }
  }

  isHashUrl(hash: string | null): boolean {
    return !!hash && (hash.startsWith('http://') || hash.startsWith('https://'));
  }

  formatAmount(n: number): string {
    return (n < 0 ? '-$' : '$') + Math.abs(n).toLocaleString('en-US', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });
  }

  getChainLabel(hash: string | null): string {
    if (!hash) return '';
    if (hash.includes('bscscan')) return 'BSC';
    if (hash.includes('etherscan')) return 'ETH';
    return '';
  }

  getSortIcon(key: SortKey): string {
    if (this.sortKey !== key) return '↕';
    return this.sortDir === 'asc' ? '↑' : '↓';
  }

  // Stats for current filter
  get filteredTotal(): number {
    return parseFloat(
      this.filteredTransactions.reduce((s, t) => s + t.amount, 0).toFixed(2)
    );
  }

  get uniqueMembers(): number {
    return new Set(this.filteredTransactions.map(t => t.name)).size;
  }
}
<!-- Loading State -->
<div class="loading-state" *ngIf="loading">
  <div class="spinner"></div>
  <p>Loading transactions...</p>
</div>

<!-- Error State -->
<div class="error-state" *ngIf="error && !loading">
  <div class="error-icon">
    <svg width="32" height="32" viewBox="0 0 24 24" fill="#f85149">
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-2h2v2zm0-4h-2V7h2v6z"/>
    </svg>
  </div>
  <h3>Connection Error</h3>
  <p>{{ error }}</p>
  <button class="retry-btn" (click)="loadTransactions()">Retry</button>
</div>

<!-- Transactions Content -->
<div class="transactions-page" *ngIf="!loading && !error">

  <!-- Page Header -->
  <div class="page-header">
    <div>
      <h1 class="page-title">Transactions</h1>
      <p class="page-subtitle">All Mar 2025 crypto payment records</p>
    </div>
  </div>

  <!-- Toolbar -->
  <div class="toolbar">
    <div class="search-box">
      <svg class="search-icon" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
        <path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0 0 16 9.5 6.5 6.5 0 1 0 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/>
      </svg>
      <input
        type="text"
        placeholder="Search by name, date, amount or hash..."
        [(ngModel)]="searchQuery"
        (ngModelChange)="onSearch()"
        class="search-input"
      />
      <button class="clear-btn" *ngIf="searchQuery" (click)="clearSearch()">
        <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
          <path d="M19 6.41L17.59 5 12 10.59 6.41 5 5 6.41 10.59 12 5 17.59 6.41 19 12 13.41 17.59 19 19 17.59 13.41 12z"/>
        </svg>
      </button>
    </div>

    <div class="toolbar-stats">
      <span class="stat-chip">
        <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M3 13h2v-2H3v2zm0 4h2v-2H3v2zm0-8h2V7H3v2zm4 4h14v-2H7v2zm0 4h14v-2H7v2zM7 7v2h14V7H7z"/></svg>
        {{ filteredTransactions.length }} records
      </span>
      <span class="stat-chip">
        <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor"><path d="M12 12c2.21 0 4-1.79 4-4s-1.79-4-4-4-4 1.79-4 4 1.79 4 4 4zm0 2c-2.67 0-8 1.34-8 4v2h16v-2c0-2.66-5.33-4-8-4z"/></svg>
        {{ uniqueMembers }} members
      </span>
      <span class="stat-chip red">
        Total: {{ formatAmount(filteredTotal) }}
      </span>
    </div>
  </div>

  <!-- Table -->
  <div class="table-card">
    <div class="table-wrapper">
      <table class="tx-table">
        <thead>
          <tr>
            <th class="th-num">#</th>
            <th class="sortable" (click)="setSort('date')">
              Date <span class="sort-icon">{{ getSortIcon('date') }}</span>
            </th>
            <th class="sortable" (click)="setSort('name')">
              Member <span class="sort-icon">{{ getSortIcon('name') }}</span>
            </th>
            <th class="sortable th-right" (click)="setSort('amount')">
              Amount <span class="sort-icon">{{ getSortIcon('amount') }}</span>
            </th>
            <th>Transaction Hash</th>
            <th>Chain</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let t of paginatedTransactions; let i = index"
              [class.row-highlight]="i % 2 === 0">
            <td class="td-num text-muted">
              {{ (currentPage - 1) * pageSize + i + 1 }}
            </td>
            <td>
              <span class="date-badge">{{ t.date }}</span>
            </td>
            <td>
              <div class="member-cell">
                <div class="member-dot"></div>
                <span class="member-name">{{ t.name }}</span>
              </div>
            </td>
            <td class="td-right amount-cell text-red">
              {{ formatAmount(t.amount) }}
            </td>
            <td class="hash-cell">
              <ng-container *ngIf="t.transactionHash; else noHash">
                <ng-container *ngIf="isHashUrl(t.transactionHash); else plainText">
                  <a [href]="t.transactionHash" target="_blank" rel="noopener" class="hash-link">
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="currentColor">
                      <path d="M19 19H5V5h7V3H5a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7h-2v7zM14 3v2h3.59l-9.83 9.83 1.41 1.41L19 6.41V10h2V3h-7z"/>
                    </svg>
                    {{ t.transactionHash }}
                  </a>
                </ng-container>
                <ng-template #plainText>
                  <span class="hash-plain">{{ t.transactionHash }}</span>
                </ng-template>
              </ng-container>
              <ng-template #noHash>
                <span class="text-muted">—</span>
              </ng-template>
            </td>
            <td>
              <span class="chain-badge" *ngIf="getChainLabel(t.transactionHash)" [class.bsc]="getChainLabel(t.transactionHash) === 'BSC'">
                {{ getChainLabel(t.transactionHash) }}
              </span>
              <span class="text-muted" *ngIf="!getChainLabel(t.transactionHash)">—</span>
            </td>
          </tr>
        </tbody>
      </table>

      <!-- Empty state -->
      <div class="empty-state" *ngIf="filteredTransactions.length === 0">
        <svg width="40" height="40" viewBox="0 0 24 24" fill="#6e7681">
          <path d="M15.5 14h-.79l-.28-.27A6.471 6.471 0 0 0 16 9.5 6.5 6.5 0 1 0 9.5 16c1.61 0 3.09-.59 4.23-1.57l.27.28v.79l5 4.99L20.49 19l-4.99-5zm-6 0C7.01 14 5 11.99 5 9.5S7.01 5 9.5 5 14 7.01 14 9.5 11.99 14 9.5 14z"/>
        </svg>
        <p>No transactions found for "<strong>{{ searchQuery }}</strong>"</p>
        <button class="retry-btn" (click)="clearSearch()">Clear search</button>
      </div>
    </div>

    <!-- Pagination -->
    <div class="pagination" *ngIf="totalPages > 1">
      <button class="page-btn" [disabled]="currentPage === 1" (click)="goToPage(currentPage - 1)">
        &larr; Prev
      </button>
      <div class="page-numbers">
        <button
          *ngFor="let p of pageNumbers"
          class="page-btn num"
          [class.active]="p === currentPage"
          (click)="goToPage(p)">
          {{ p }}
        </button>
      </div>
      <button class="page-btn" [disabled]="currentPage === totalPages" (click)="goToPage(currentPage + 1)">
        Next &rarr;
      </button>
    </div>
  </div>

</div>
